import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";
import { useMemo } from "react";

interface ReactionCounts {
  likes: number;
  dislikes: number;
}

// Generate or retrieve a persistent visitor ID for anonymous users
function getVisitorId(): string {
  const key = "xiaoxiong_visitor_id";
  let id = localStorage.getItem(key);
  if (!id) {
    id = crypto.randomUUID();
    localStorage.setItem(key, id);
  }
  return id;
}

/**
 * Hook for story reactions. Supports both restaurant stories and homepage template stories.
 * Pass either restaurantId OR templateId (not both).
 */
export function useStoryReactions(targetId: string | undefined, targetType: "restaurant" | "template" = "restaurant") {
  const { user } = useAuth();
  const queryClient = useQueryClient();
  const visitorId = useMemo(() => (user ? null : getVisitorId()), [user]);

  const targetColumn = targetType === "template" ? "template_id" : "restaurant_id";

  const { data: counts = { likes: 0, dislikes: 0 } } = useQuery<ReactionCounts>({
    queryKey: ["story-reactions-counts", targetType, targetId],
    queryFn: async () => {
      const { data, error } = await supabase
        .from("story_reactions" as any)
        .select("reaction_type")
        .eq(targetColumn, targetId!);
      if (error) throw error;
      const items = data as any[];
      return {
        likes: items.filter((r) => r.reaction_type === "like").length,
        dislikes: items.filter((r) => r.reaction_type === "dislike").length,
      };
    },
    enabled: !!targetId,
  });

  const identifierKey = user ? "user_id" : "visitor_id";
  const identifierValue = user ? user.id : visitorId;

  const { data: userReaction } = useQuery<string | null>({
    queryKey: ["story-reaction-user", targetType, targetId, identifierKey, identifierValue],
    queryFn: async () => {
      const { data, error } = await supabase
        .from("story_reactions" as any)
        .select("reaction_type")
        .eq(targetColumn, targetId!)
        .eq(identifierKey, identifierValue!)
        .maybeSingle();
      if (error) throw error;
      return (data as any)?.reaction_type || null;
    },
    enabled: !!targetId && !!identifierValue,
  });

  const toggleReaction = useMutation({
    mutationFn: async (type: "like" | "dislike") => {
      if (!targetId || !identifierValue) throw new Error("Missing identifier");

      if (userReaction === type) {
        // Remove reaction
        await supabase
          .from("story_reactions" as any)
          .delete()
          .eq(targetColumn, targetId)
          .eq(identifierKey, identifierValue);
      } else if (userReaction) {
        // Change reaction
        await supabase
          .from("story_reactions" as any)
          .update({ reaction_type: type } as any)
          .eq(targetColumn, targetId)
          .eq(identifierKey, identifierValue);
      } else {
        // New reaction
        const record: any = {
          [targetColumn]: targetId,
          reaction_type: type,
        };
        if (user) {
          record.user_id = user.id;
        } else {
          record.visitor_id = visitorId;
        }
        await supabase
          .from("story_reactions" as any)
          .insert(record);
      }
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["story-reactions-counts", targetType, targetId] });
      queryClient.invalidateQueries({ queryKey: ["story-reaction-user", targetType, targetId, identifierKey, identifierValue] });
    },
  });

  return { counts, userReaction: userReaction ?? null, toggleReaction };
}
